        length(X,N),
        X :: 1..N,

        N1 is N-1,
        length(Diffs,N1),
        Diffs :: 1..N1,

        SumDistinct is ((N+1)*N) div 2,

        alldifferent(X),
        alldifferent(Diffs),

        foreach(K in 1..N1, Diffs[K] #= abs(X[K+1] - X[K])),

        % symmetry breaking
        X[1] #< X[N1],
