    }

    // Constraints
    // Lines constraint
    s.add(distinct(x));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i != j) {
                // Diago constraint
                s.add(x[i] != x[j] - abs(j - i));
                s.add(x[i] != x[j] + abs(j - i));
            }
        }
    }

