function void across(var<CP>{int}[,] Matrix, var<CP>{int} Across, int Len, int Row, int Col) {

  Solver<CP> m = Matrix[1,1].getSolver();
  var<CP>{int} tmp[1..Len](m, 0..9999);

  toNum10(tmp, Across);
  forall(i in 0..Len-1) {
